    }

    // Final timeout check - if either sensor timed out after processing input, force SAFE_VENT
    if (pressure_timed_out || door_timed_out) {
        s_controller.compressor_on = false;
        s_controller.vent_open = true;
        s_controller.state = CONTROLLER_STATE_SAFE_VENT;
